worked_example.final_code:
import java.util.*;
import java.util.concurrent.*;
import java.util.stream.*;
import com.fasterxml.jackson.databind.*;

record StockQuote(String symbol, double price, double changePercent) {
    boolean isUnknown() { return price == 0; }
    static StockQuote unknown(String sym) { return new StockQuote(sym, 0, 0); }
}

public class AsyncStockAggregator {
    private static final ObjectMapper MAPPER = new ObjectMapper();

    // Simulates sendAsync + thenApply parse:
    static CompletableFuture<StockQuote> fetchAsync(String symbol) {
        return CompletableFuture.supplyAsync(() -> {
            try { Thread.sleep(50 + (int)(Math.random() * 80)); }
            catch (InterruptedException e) { Thread.currentThread().interrupt(); }

            Map<String, double[]> data = Map.of(
                "TCS",      new double[]{3890, 4.1},
                "RELIANCE", new double[]{2450, 1.2},
                "INFY",     new double[]{1560, -3.8},
                "HDFC",     new double[]{1679, 0.8},
                "WIPRO",    new double[]{412, -1.1}
            );
            if (!data.containsKey(symbol))
                throw new RuntimeException("HTTP 404: " + symbol);
            double[] d = data.get(symbol);
            return new StockQuote(symbol, d[0], d[1]);
        }).exceptionally(ex -> {
            System.out.printf("  [%-8s] ERROR: %s%n", symbol, ex.getCause().getMessage());
            return StockQuote.unknown(symbol);
        });
    }

    public static void main(String[] args) throws Exception {
        List<String> symbols = List.of("TCS", "RELIANCE", "INFY", "HDFC", "WIPRO", "BADSTOCK");
        long start = System.currentTimeMillis();

        System.out.println("Fetching " + symbols.size() + " quotes in parallel...");

        List<CompletableFuture<StockQuote>> futures = symbols.stream()
            .map(AsyncStockAggregator::fetchAsync)
            .collect(Collectors.toList());

        CompletableFuture.allOf(futures.toArray(new CompletableFuture[0]))
            .thenRun(() -> {
                long ms = System.currentTimeMillis() - start;
                List<StockQuote> valid = futures.stream()
                    .map(CompletableFuture::join)
                    .filter(q -> !q.isUnknown())
                    .sorted((a, b) -> Double.compare(b.changePercent(), a.changePercent()))
                    .collect(Collectors.toList());

                System.out.printf("%nFetched %d quotes in %dms (sequential would be ~%dms)%n%n",
                    valid.size(), ms, symbols.size() * 90);
                System.out.printf("%-12s %8s  %8s  %12s%n", "Symbol", "Price", "Change", "Value@10");
                System.out.println("-".repeat(45));
                valid.forEach(q -> System.out.printf("%-12s ₹%,6.0f  %+6.1f%%  ₹%,10.0f%n",
                    q.symbol(), q.price(), q.changePercent(), q.price() * 10));

                double total = valid.stream().mapToDouble(q -> q.price() * 10).sum();
                System.out.printf("%n%-12s %8s  %8s  ₹%,10.0f%n", "TOTAL", "", "", total);

                valid.stream().max(Comparator.comparingDouble(StockQuote::changePercent))
                    .ifPresent(top -> System.out.println("\nTop mover: " + top.symbol() +
                        " at " + String.format("%+.1f%%", top.changePercent())));
            })
            .join();
    }
}

